import numpy as np

def Rx(theta):
    c, s = np.cos(theta/2), np.sin(theta/2)
    return np.array([[c, -1j*s], [-1j*s, c]])

def Ry(theta):
    c, s = np.cos(theta/2), np.sin(theta/2)
    return np.array([[c, -s], [s, c]])

def Rz(theta):
    return np.array([[np.exp(-1j*theta/2), 0], [0, np.exp(1j*theta/2)]])

def state_to_bloch(state):
    """Convert state to (x, y, z) Bloch coordinates."""
    state = state / np.linalg.norm(state)
    X = np.array([[0, 1], [1, 0]])
    Y = np.array([[0, -1j], [1j, 0]])
    Z = np.array([[1, 0], [0, -1]])

    x = np.real(state.conj() @ X @ state)
    y = np.real(state.conj() @ Y @ state)
    z = np.real(state.conj() @ Z @ state)
    return (x, y, z)

def trace_rotation(R_func, initial_state, n_steps=8):
    """Trace the Bloch sphere path."""
    path = []
    for i in range(n_steps + 1):
        theta = 2 * np.pi * i / n_steps
        rotated = R_func(theta) @ initial_state
        x, y, z = state_to_bloch(rotated)
        path.append((theta, x, y, z))
    return path

# Trace |+⟩ under each rotation
plus = np.array([1, 1]) / np.sqrt(2)

print("Bloch sphere trajectories starting from |+⟩ = (1,0,0):")
for name, R in [('Rx', Rx), ('Ry', Ry), ('Rz', Rz)]:
    print(f"\n{name} rotation of |+⟩:")
    path = trace_rotation(R, plus)
    for theta, x, y, z in path:
        print(f"  θ={np.degrees(theta):>5.0f}°: ({x:>6.3f}, {y:>6.3f}, {z:>6.3f})")

    # Describe the path
    if name == 'Rx':
        print("  → Circle in YZ plane (x stays ~1, rotates in y-z)")
    elif name == 'Ry':
        print("  → Circle in XZ plane (y stays ~0, rotates in x-z)")
    else:
        print("  → Circle in XY plane (z stays ~0, rotates in x-y)")
